#include <stdio.h>

int gcd(int a, int b) {
    if (a == 0) return b;
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    printf("GCD: %d\n", gcd(48, 0));
    return 0;
}
